async function main() {
    console.log(`\n🎬 Ajout de ${CLASSICS.length} films classiques en base...\n`);
    let created = 0;
    let updated = 0;
    let skipped = 0;
    for (const film of CLASSICS) {
        // Déduplication par tmdbId ou titre exact
        const existing = await prisma.film.findFirst({
            where: {
                OR: [
                    ...(film.tmdbId ? [{ tmdbId: film.tmdbId }] : []),
                    { titre: { equals: film.titre, mode: "insensitive" } },
                ],
            },
        });
        if (existing) {
            const needsUpdate = !existing.affiche || !existing.synopsis || !existing.annee || !existing.tmdbId;
            if (needsUpdate) {
                try {
                    await prisma.film.update({
                        where: { id: existing.id },
                        data: {
                            tmdbId: existing.tmdbId ?? film.tmdbId,
                            affiche: existing.affiche ?? film.affiche,
                            synopsis: existing.synopsis ?? film.synopsis,
                            annee: existing.annee ?? film.annee,
                            genres: existing.genres.length > 0 ? existing.genres : film.genres,
                            realisateur: existing.realisateur ?? film.realisateur,
                            acteurs: existing.acteurs.length > 0 ? existing.acteurs : film.acteurs,
                            duree: existing.duree ?? film.duree,
                        },
                    });
                    console.log(`  🔄 Mis à jour : ${film.titre}`);
                    updated++;
                }
                catch {
                    console.log(`  ⚠️  Conflit de mise à jour ignoré : ${film.titre}`);
                    skipped++;
                }
            }
            else {
                skipped++;
            }
            continue;
        }
        // Évite les erreurs de contrainte unique sur tmdbId si doublon dans le script
        try {
            await prisma.film.create({
                data: {
                    titre: film.titre,
                    titreOriginal: film.titreOriginal,
                    synopsis: film.synopsis,
                    affiche: film.affiche,
                    duree: film.duree,
                    genres: film.genres,
                    realisateur: film.realisateur,
                    acteurs: film.acteurs,
                    annee: film.annee,
                    tmdbId: film.tmdbId,
                },
            });
            console.log(`  ✅ Créé : ${film.titre} (${film.annee})`);
            created++;
        }
        catch {
            console.log(`  ⚠️  Ignoré (conflit) : ${film.titre}`);
            skipped++;
        }
    }
    console.log(`
📊 Résultat :
   ${created} films créés
   ${updated} films mis à jour
   ${skipped} films ignorés (déjà présents ou conflit)
  `);
    await prisma.$disconnect();
}
main().catch((err) => {
    console.error(err);
    process.exit(1);
});
